// English name for a key-item id, or 0 if unknown.
inline const char* key_item_name(unsigned id) {
    int lo = 0, hi = KEY_ITEMS_N - 1;
    while (lo <= hi) { const int mid = (lo + hi) >> 1; const unsigned m = KEY_ITEMS[mid].id;
        if (m == id) return KEY_ITEMS[mid].en; if (m < id) lo = mid + 1; else hi = mid - 1; }
    return 0;
}

